namespace Haven.Finance.MasterDataImport.Web.Services;

/// <summary>
/// Attaches the user's Bearer token to outgoing API requests.
/// </summary>
public sealed class CustomAuthorizationMessageHandler : AuthorizationMessageHandler
{
    public CustomAuthorizationMessageHandler(
        IAccessTokenProvider provider,
        NavigationManager navigation)
        : base(provider, navigation)
    {
        ConfigureHandler(authorizedUrls: [navigation.BaseUri]);
    }
}
