#### 1d. Modify `Program.cs`
Replace the plain HttpClient registration with MSAL + named HttpClient pattern:

```csharp
using Microsoft.AspNetCore.Components.Web;
using Microsoft.AspNetCore.Components.WebAssembly.Hosting;

var builder = WebAssemblyHostBuilder.CreateDefault(args);
builder.RootComponents.Add<Haven.Finance.MasterDataImport.Web.Components.App>("#app");
builder.RootComponents.Add<HeadOutlet>("head::after");

builder.Services.AddMsalAuthentication(options =>
{
    builder.Configuration.Bind("AzureAd", options.ProviderOptions.Authentication);
    options.ProviderOptions.DefaultAccessTokenScopes.Add(
        $"api://{builder.Configuration["AzureAd:ClientId"]}/access_as_user");
    options.ProviderOptions.LoginMode = "redirect";
});

builder.Services.AddTransient<CustomAuthorizationMessageHandler>();

var apiBaseUrl = builder.Configuration["ApiBaseUrl"];
var baseAddress = string.IsNullOrWhiteSpace(apiBaseUrl)
    ? new Uri(builder.HostEnvironment.BaseAddress)
    : new Uri(apiBaseUrl);

builder.Services.AddHttpClient("API", client =>
{
    client.BaseAddress = baseAddress;
    client.Timeout = TimeSpan.FromMinutes(5);
}).AddHttpMessageHandler<CustomAuthorizationMessageHandler>();

builder.Services.AddScoped(sp =>
    sp.GetRequiredService<IHttpClientFactory>().CreateClient("API"));
builder.Services.AddScoped<ImportService>();

await builder.Build().RunAsync();
```

