```csharp
// Origin verification ŌĆö non-Development environments only.
// Rejects requests without the CloudFront X-Origin-Verify header.
if (!app.Environment.IsDevelopment())
{
    var ssmParamName = Environment.GetEnvironmentVariable("CLOUDFRONT_ORIGIN_VERIFY_SSM_NAME");
    if (!string.IsNullOrWhiteSpace(ssmParamName))
    {
        using var ssmClient = new Amazon.SimpleSystemsManagement.AmazonSimpleSystemsManagementClient();
        var ssmResponse = await ssmClient.GetParameterAsync(
            new Amazon.SimpleSystemsManagement.Model.GetParameterRequest
            {
                Name = ssmParamName,
                WithDecryption = true
            }).ConfigureAwait(false);
        var originVerifySecret = ssmResponse.Parameter.Value;

        app.Use(async (context, next) =>
        {
            // Allow static files through without origin verification
            var path = context.Request.Path.Value ?? "";
            if (path.StartsWith("/api/", StringComparison.OrdinalIgnoreCase)
                || path.Equals("/run", StringComparison.OrdinalIgnoreCase))
            {
                if (!context.Request.Headers.TryGetValue("X-Origin-Verify", out var headerValue)
                    || headerValue != originVerifySecret)
                {
                    context.Response.StatusCode = StatusCodes.Status403Forbidden;
                    return;
                }
            }

            await next().ConfigureAwait(false);
        });
    }
}

app.UseAuthentication();
app.UseAuthorization();
```

