The middleware:
```csharp
namespace Haven.Finance.MasterDataImport.Lambda.Harness.Middleware;

/// <summary>
/// Rejects API requests that do not carry the correct X-Origin-Verify header.
/// Used in non-Development environments to ensure requests come through CloudFront.
/// </summary>
public sealed class OriginVerificationMiddleware(RequestDelegate next, string expectedSecret)
{
    private const string HeaderName = "X-Origin-Verify";

    public async Task InvokeAsync(HttpContext context)
    {
        var path = context.Request.Path.Value ?? "";
        if (path.StartsWith("/api/", StringComparison.OrdinalIgnoreCase)
            || path.Equals("/run", StringComparison.OrdinalIgnoreCase))
        {
            if (!context.Request.Headers.TryGetValue(HeaderName, out var headerValue)
                || headerValue != expectedSecret)
            {
                context.Response.StatusCode = StatusCodes.Status403Forbidden;
                return;
            }
        }

        await next(context).ConfigureAwait(false);
    }
}
```

