using Microsoft.AspNetCore.Http;

namespace Haven.Finance.MasterDataImport.Lambda.Tests.Harness;

public sealed class OriginVerificationMiddlewareShould
{
    private const string Secret = "test-secret-123";

    [Theory]
    [InlineData("/api/upload")]
    [InlineData("/api/run")]
    [InlineData("/api/result")]
    [InlineData("/run")]
    public async Task RejectApiRequestsWithoutHeader(string path)
    {
        var middleware = CreateMiddleware();
        var context = CreateContext(path);

        await middleware.InvokeAsync(context);

        Assert.Equal(403, context.Response.StatusCode);
    }

    [Theory]
    [InlineData("/api/upload")]
    [InlineData("/api/run")]
    public async Task RejectApiRequestsWithWrongHeader(string path)
    {
        var middleware = CreateMiddleware();
        var context = CreateContext(path);
        context.Request.Headers["X-Origin-Verify"] = "wrong-secret";

        await middleware.InvokeAsync(context);

        Assert.Equal(403, context.Response.StatusCode);
    }

    [Theory]
    [InlineData("/api/upload")]
    [InlineData("/api/run")]
    [InlineData("/api/result")]
    [InlineData("/run")]
    public async Task AllowApiRequestsWithCorrectHeader(string path)
    {
        var nextCalled = false;
        var middleware = CreateMiddleware(() => nextCalled = true);
        var context = CreateContext(path);
        context.Request.Headers["X-Origin-Verify"] = Secret;

        await middleware.InvokeAsync(context);

        Assert.True(nextCalled);
        Assert.Equal(200, context.Response.StatusCode);
    }

    [Theory]
    [InlineData("/")]
    [InlineData("/_framework/blazor.webassembly.js")]
    [InlineData("/index.html")]
    [InlineData("/app.css")]
    public async Task AllowStaticFileRequestsWithoutHeader(string path)
    {
        var nextCalled = false;
        var middleware = CreateMiddleware(() => nextCalled = true);
        var context = CreateContext(path);

        await middleware.InvokeAsync(context);

        Assert.True(nextCalled);
        Assert.Equal(200, context.Response.StatusCode);
    }

    private static OriginVerificationMiddleware CreateMiddleware(Action? onNext = null)
    {
        return new OriginVerificationMiddleware(
            _ =>
            {
                onNext?.Invoke();
                return Task.CompletedTask;
            },
            Secret);
    }

    private static DefaultHttpContext CreateContext(string path)
    {
        var context = new DefaultHttpContext();
        context.Request.Path = path;
        return context;
    }
}
